INSERT INTO `units` VALUES (1,'Dinas','dinas',NULL,'2025-09-12 20:42:34','2025-09-12 20:43:34'),(2,'Sekretariat','sekretariat','Sekretariat Dinas Pekerjaan Umum, Perumahan dan Kawasan Permukiman adalah satuan organisasi yang melakasanakan pekerjaan office service atau jasa-jasa perkantoran, misalnya dalam hal penyambungan telepon, pengadaan dan pemeliharaan mesin-mesin kantor, tata ruang kantor, pembuatan formulir, komputerisasi, surat menyurat dan kearsipan.','2025-09-13 00:20:47','2025-09-15 18:20:59'),(3,'UPTD Sumoroto','uptd-sumoroto','UPTD DPUPKP yang bertanggung jawab atas pengelolaan infrastruktur di wilayah Babadan. Tugasnya mencakup pemeliharaan jalan, pengelolaan jaringan irigasi, serta perawatan infrastruktur permukiman di Wilayah Sumoroto.','2025-09-15 18:19:24','2025-09-15 18:19:24'),(4,'UPTD Sambit','uptd-sambit','UPTD DPUPKP yang bertanggung jawab atas pengelolaan infrastruktur di wilayah Sambit. Tugasnya mencakup pemeliharaan jalan, pengelolaan jaringan irigasi, serta perawatan infrastruktur permukiman','2025-09-15 18:19:35','2025-09-15 18:25:48'),(5,'UPTD IPALD','uptd-ipald','UPTD IPALD (Unit Pelaksana Teknis Daerah Instalasi Pengolahan Air Limbah Domestik) adalah unit teknis yang bertugas mengelola dan mengoperasikan instalasi pengolahan air limbah domestik di suatu wilayah. Fungsinya meliputi pengolahan limbah rumah tangga, seperti air buangan dari dapur, kamar mandi, dan toilet, agar tidak mencemari lingkungan.','2025-09-15 18:20:38','2025-09-15 18:20:38'),(6,'Bidang Sumber Daya Air','bidang-sumber-daya-air','Bidang Sumber Daya Air Dinas Pekerjaan Umum, Perumahan dan Kawasan Permukiman adalah bidang yang mempunyai tugas mengumpulkan bahan, koordinasi dan melaksanakan pengaturan, pembinaan, bantuan teknis, pembangunan, rehabilitasi dan pemanfaatan sumber daya air.','2025-09-15 18:21:25','2025-09-15 18:21:25'),(7,'Bidang Bina Marga','bidang-bina-marga','Bidang Bina Marga adalah bagian dari organisasi atau institusi, terutama di tingkat pemerintahan, yang fokus utamanya adalah pada perencanaan, pembangunan, pemeliharaan, dan pengelolaan jalan serta jembatan. Bidang ini berada di bawah Dinas Pekerjaan Umum atau Kementerian PUPR (Pekerjaan Umum dan Perumahan Rakyat) di tingkat daerah maupun nasional.','2025-09-15 18:21:48','2025-09-15 18:21:48'),(8,'Bidang Penataan Ruang','bidang-penataan-ruang','Bidang Penataan Ruang merupakan salah satu bidang di Dinas Pekerjaan Umum, Perumahan dan Kawasan Permukiman yang memiliki fungsi dalam penyelenggaraan penataan ruang di Kabupaten Ponorogo yang meliputi pengaturan, pembinaan, pelaksanaan, dan pengawasan Penataan Ruang.','2025-09-15 18:22:20','2025-09-15 18:22:20'),(9,'Bidang Perumahan dan Tata Bangunan','bidang-perumahan-dan-tata-bangunan','Bidang Perumahan dan Tata Bangunan adalah bidang yang bertanggung jawab atas pengelolaan dan pengaturan pembangunan perumahan serta bangunan di suatu wilayah.','2025-09-15 18:22:59','2025-09-15 18:22:59'),(10,'Bidang Kawasan Permukiman','bidang-kawasan-permukiman','Bidang Kawasan Permukiman bertanggung jawab atas perencanaan dan pengelolaan permukiman yang layak huni, aman, dan nyaman, serta penataan kawasan kumuh.','2025-09-15 18:23:31','2025-09-15 18:23:31'),(11,'Bidang Bina Konstruksi dan Pengendalian Mutu','bidang-bina-konstruksi-dan-pengendalian-mutu','Bidang Bina konstruksi mempunyai tugas menyelenggarakan pelaksanaan kebijakan di bidang pembinaan jasa konstruksi sesuai dengan ketentuan peraturan perundang-undangan yang berlaku','2025-09-15 18:24:11','2025-09-15 18:24:11'),(12,'UPTD Karangan','uptd-karangan','UPTD DPUPKP yang bertanggung jawab atas pengelolaan infrastruktur di wilayah Karangan. Tugasnya mencakup pemeliharaan jalan, pengelolaan jaringan irigasi, serta perawatan infrastruktur permukiman di Wilayah Karangan.','2025-09-15 18:27:23','2025-09-15 18:27:23'),(13,'UPTD Babadan','uptd-babadan','UPTD DPUPKP yang bertanggung jawab atas pengelolaan infrastruktur di wilayah Babadan. Tugasnya mencakup pemeliharaan jalan, pengelolaan jaringan irigasi, serta perawatan infrastruktur permukiman di Wilayah Babadan.','2025-09-15 18:28:02','2025-09-15 18:28:02'),(14,'UPTD Pulung','uptd-pulung','UPTD DPUPKP yang bertanggung jawab atas pengelolaan infrastruktur di wilayah Babadan. Tugasnya mencakup pemeliharaan jalan, pengelolaan jaringan irigasi, serta perawatan infrastruktur permukiman di Wilayah Pulung','2025-09-15 18:28:42','2026-01-29 06:39:11');
